#!/usr/bin/env node
'use strict';

const fs = require('fs');
const path = require('path');

const esbuild = require('esbuild');

const repoRoot = path.resolve(__dirname, '..');
const useBuildOutput = process.argv.includes('--build-output');
const runtimeRoot = useBuildOutput ? path.join(repoRoot, '.build') : repoRoot;

function resolveEntryPoint() {
  if (useBuildOutput) {
    return path.join(runtimeRoot, 'electron', 'preload', 'canva.js');
  }

  const tsEntry = path.join(runtimeRoot, 'electron', 'preload', 'canva.ts');
  if (fs.existsSync(tsEntry)) {
    return tsEntry;
  }

  return path.join(runtimeRoot, 'electron', 'preload', 'canva.js');
}

async function main() {
  const entryPoint = resolveEntryPoint();
  const outputFile = path.join(runtimeRoot, 'electron', 'preload', 'canva.bundle.js');

  if (!fs.existsSync(entryPoint)) {
    throw new Error(`[preload-bundle] missing entrypoint: ${path.relative(repoRoot, entryPoint)}`);
  }

  await esbuild.build({
    entryPoints: [entryPoint],
    outfile: outputFile,
    bundle: true,
    platform: 'node',
    target: 'es2022',
    format: 'cjs',
    external: ['electron'],
    sourcemap: false,
    minify: false,
    legalComments: 'none',
    logLevel: 'info',
    banner: {
      js: [
        '// Generated by scripts/build-preload-bundle.js using esbuild.',
        '// Do not edit this file directly. Edit electron/preload source modules instead.',
        "'use strict';",
      ].join('\n'),
    },
  });

  console.log(`[preload-bundle] wrote ${path.relative(repoRoot, outputFile)}`);
}

main().catch((error) => {
  console.error(error.message || error);
  process.exit(1);
});
